CREATE OR REPLACE FUNCTION document_ut.test_canvas_create()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id uuid;
  v_row document.canvas;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  -- Default A4 portrait
  v_id := document.canvas_create('Test A4');
  SELECT * INTO v_row FROM document.canvas WHERE id = v_id;
  RETURN NEXT ok(v_row.id IS NOT NULL, 'canvas created');
  RETURN NEXT is(v_row.name, 'Test A4', 'name matches');
  RETURN NEXT is(v_row.format, 'A4', 'format A4');
  RETURN NEXT is(v_row.orientation, 'portrait', 'portrait');
  RETURN NEXT ok(v_row.width = 794, 'A4 width 794');
  RETURN NEXT ok(v_row.height = 1123, 'A4 height 1123');

  -- Landscape
  v_id := document.canvas_create('Test landscape', 'A4', 'paysage');
  SELECT * INTO v_row FROM document.canvas WHERE id = v_id;
  RETURN NEXT ok(v_row.width > v_row.height, 'landscape width > height');

  -- Custom dimensions
  v_id := document.canvas_create('Custom', 'CUSTOM', 'portrait', 500, 800);
  SELECT * INTO v_row FROM document.canvas WHERE id = v_id;
  RETURN NEXT ok(v_row.width = 500, 'custom width');
  RETURN NEXT ok(v_row.height = 800, 'custom height');

  -- Cleanup
  DELETE FROM document.canvas WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION document_ut.test_canvas_create() IS 'Test canvas creation with formats and dimensions';

CREATE OR REPLACE FUNCTION document_ut.test_canvas_duplicate()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_src_id uuid;
  v_dup_id uuid;
  v_src_state jsonb;
  v_dup_state jsonb;
  v_src_elem_ids jsonb;
  v_dup_elem_ids jsonb;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  -- Create source canvas with elements
  v_src_id := document.canvas_create('Original');
  PERFORM document.element_add(v_src_id, 'rect', 0, '{"x":0,"y":0,"width":100,"height":50}'::jsonb);
  PERFORM document.element_add(v_src_id, 'text', 1, '{"x":10,"y":20}'::jsonb);

  -- Duplicate
  v_dup_id := document.canvas_duplicate(v_src_id, 'Copy');

  -- Verify canvas
  v_src_state := document.canvas_get_state(v_src_id);
  v_dup_state := document.canvas_get_state(v_dup_id);

  RETURN NEXT ok(v_dup_id IS NOT NULL, 'duplicate created');
  RETURN NEXT ok(v_dup_id != v_src_id, 'different canvas ID');
  RETURN NEXT is(v_dup_state->>'name', 'Copy', 'duplicate name');
  RETURN NEXT is(v_dup_state->>'format', v_src_state->>'format', 'same format');
  RETURN NEXT ok(
    jsonb_array_length(v_dup_state->'elements') = jsonb_array_length(v_src_state->'elements'),
    'same element count'
  );

  -- Verify element IDs are different
  SELECT jsonb_agg(e->>'id') INTO v_src_elem_ids FROM jsonb_array_elements(v_src_state->'elements') e;
  SELECT jsonb_agg(e->>'id') INTO v_dup_elem_ids FROM jsonb_array_elements(v_dup_state->'elements') e;
  RETURN NEXT ok(v_src_elem_ids != v_dup_elem_ids, 'element IDs are different');

  -- Cleanup
  DELETE FROM document.canvas WHERE id IN (v_src_id, v_dup_id);
END;
$function$;
COMMENT ON FUNCTION document_ut.test_canvas_duplicate() IS 'Test canvas_duplicate deep copies with new IDs';

CREATE OR REPLACE FUNCTION document_ut.test_canvas_get_state()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_canvas_id uuid;
  v_group_id uuid;
  v_state jsonb;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  v_canvas_id := document.canvas_create('State test');

  -- Add group
  v_group_id := document.element_add(v_canvas_id, 'group', 0, '{"name":"header"}'::jsonb);

  -- Add child rect in group
  PERFORM document.element_add(v_canvas_id, 'rect', 1,
    jsonb_build_object('x',0,'y',0,'width',100,'height',50,'parent_id', v_group_id));

  -- Add standalone text
  PERFORM document.element_add(v_canvas_id, 'text', 2, '{"x":10,"y":200}'::jsonb);

  -- Get state
  v_state := document.canvas_get_state(v_canvas_id);
  RETURN NEXT ok(v_state IS NOT NULL, 'state returned');
  RETURN NEXT is(v_state->>'name', 'State test', 'canvas name in state');
  RETURN NEXT ok(v_state ? 'elements', 'has elements key');
  RETURN NEXT ok(v_state ? 'gradients', 'has gradients key');
  RETURN NEXT ok(jsonb_array_length(v_state->'elements') = 3, '3 elements (group + rect + text)');

  -- Verify group element has children via parent_id
  RETURN NEXT ok(
    (SELECT count(*) FROM jsonb_array_elements(v_state->'elements') e WHERE e->>'parent_id' IS NOT NULL) = 1,
    '1 element has parent_id'
  );

  -- Cleanup
  DELETE FROM document.canvas WHERE id = v_canvas_id;
END;
$function$;
COMMENT ON FUNCTION document_ut.test_canvas_get_state() IS 'Test canvas_get_state returns full state with nested elements';

CREATE OR REPLACE FUNCTION document_ut.test_company()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_row document.company;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  -- Initially no company
  v_row := document.company_info();
  RETURN NEXT ok(v_row.id IS NULL, 'no company initially');

  -- Upsert: create
  v_row := document.set_company('Acme SAS', '12345678901234', 'FR12345678901', '1 rue Test', 'Paris', '75001', '0100000000', 'test@acme.fr', 'https://acme.fr', 'RCS Paris');
  RETURN NEXT ok(v_row.id IS NOT NULL, 'company created');
  RETURN NEXT is(v_row.name, 'Acme SAS', 'name matches');
  RETURN NEXT is(v_row.siret, '12345678901234', 'siret matches');
  RETURN NEXT is(v_row.city, 'Paris', 'city matches');

  -- Upsert: update
  v_row := document.set_company('Acme SAS Updated', '12345678901234');
  RETURN NEXT is(v_row.name, 'Acme SAS Updated', 'name updated');

  -- Get
  v_row := document.company_info();
  RETURN NEXT is(v_row.name, 'Acme SAS Updated', 'company_info returns updated');

  -- Cleanup
  DELETE FROM document.company WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION document_ut.test_company() IS 'Test company upsert and retrieval';

CREATE OR REPLACE FUNCTION document_ut.test_current_user_id()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_uid text;
BEGIN
  -- Default (no app.user_id set): returns 'dev'
  PERFORM set_config('app.user_id', '', true);
  v_uid := document.current_user_id();
  RETURN NEXT is(v_uid, 'dev', 'default returns dev');

  -- With app.user_id set
  PERFORM set_config('app.user_id', 'test-user-42', true);
  v_uid := document.current_user_id();
  RETURN NEXT is(v_uid, 'test-user-42', 'returns app.user_id when set');

  -- Reset
  PERFORM set_config('app.user_id', '', true);
  v_uid := document.current_user_id();
  RETURN NEXT is(v_uid, 'dev', 'back to dev after reset');
END;
$function$;
COMMENT ON FUNCTION document_ut.test_current_user_id() IS 'Test current_user_id resolution: app.user_id > ''dev''';

CREATE OR REPLACE FUNCTION document_ut.test_data_documents()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_tpl_id uuid;
  v_doc_id1 uuid;
  v_doc_id2 uuid;
  v_result jsonb;
  v_row jsonb;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  -- Setup
  INSERT INTO document.template (name, doc_type) VALUES ('TPL test', 'facture')
  RETURNING id INTO v_tpl_id;

  INSERT INTO document.document (template_id, doc_type, title, status)
  VALUES (v_tpl_id, 'facture', 'Doc A', 'draft')
  RETURNING id INTO v_doc_id1;

  INSERT INTO document.document (template_id, doc_type, title, status)
  VALUES (v_tpl_id, 'devis', 'Doc B', 'generated')
  RETURNING id INTO v_doc_id2;

  -- Test: format
  v_result := document.data_documents('{}');
  RETURN NEXT ok(v_result ? 'rows', 'result has rows key');
  RETURN NEXT ok(v_result ? 'has_more', 'result has has_more key');
  RETURN NEXT ok(jsonb_array_length(v_result->'rows') >= 2, 'at least 2 rows');

  -- Test: row has 7 columns (id, title, doc_type, ref_module, ref_id, status, created)
  v_row := (v_result->'rows')->0;
  RETURN NEXT ok(jsonb_array_length(v_row) = 7, 'each row has 7 columns');

  -- Test: status filter
  v_result := document.data_documents('{"p_status":"draft"}');
  RETURN NEXT ok(jsonb_array_length(v_result->'rows') >= 1, 'status filter works');

  -- Test: doc_type filter
  v_result := document.data_documents('{"p_doc_type":"devis"}');
  RETURN NEXT ok(jsonb_array_length(v_result->'rows') >= 1, 'doc_type filter works');

  -- Test: pagination
  v_result := document.data_documents('{"_size":1}');
  RETURN NEXT ok((v_result->>'has_more')::boolean, 'has_more true with size=1');

  v_result := document.data_documents('{"_size":1,"_offset":1}');
  RETURN NEXT ok(jsonb_array_length(v_result->'rows') >= 1, 'offset pagination works');

  -- Cleanup
  DELETE FROM document.document WHERE id IN (v_doc_id1, v_doc_id2);
  DELETE FROM document.template WHERE id = v_tpl_id;
END;
$function$;
COMMENT ON FUNCTION document_ut.test_data_documents() IS 'Test data_documents cursor format, filters, and pagination';

