CREATE OR REPLACE FUNCTION document_ut.test_element_constraints()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_canvas_id uuid;
  v_ok boolean;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  v_canvas_id := document.canvas_create('Test constraints');

  -- rect without width should fail
  BEGIN
    PERFORM document.element_add(v_canvas_id, 'rect', 0, '{"x":0,"y":0,"height":50}'::jsonb);
    v_ok := false;
  EXCEPTION WHEN check_violation THEN
    v_ok := true;
  END;
  RETURN NEXT ok(v_ok, 'rect without width rejected');

  -- line without x2/y2 should fail
  BEGIN
    PERFORM document.element_add(v_canvas_id, 'line', 0, '{"x1":0,"y1":0}'::jsonb);
    v_ok := false;
  EXCEPTION WHEN check_violation THEN
    v_ok := true;
  END;
  RETURN NEXT ok(v_ok, 'line without x2/y2 rejected');

  -- circle without r should fail
  BEGIN
    PERFORM document.element_add(v_canvas_id, 'circle', 0, '{"cx":50,"cy":50}'::jsonb);
    v_ok := false;
  EXCEPTION WHEN check_violation THEN
    v_ok := true;
  END;
  RETURN NEXT ok(v_ok, 'circle without r rejected');

  -- ellipse without rx/ry should fail
  BEGIN
    PERFORM document.element_add(v_canvas_id, 'ellipse', 0, '{"cx":50,"cy":50}'::jsonb);
    v_ok := false;
  EXCEPTION WHEN check_violation THEN
    v_ok := true;
  END;
  RETURN NEXT ok(v_ok, 'ellipse without rx/ry rejected');

  -- text without x/y should fail
  BEGIN
    PERFORM document.element_add(v_canvas_id, 'text', 0, '{"fill":"#000"}'::jsonb);
    v_ok := false;
  EXCEPTION WHEN check_violation THEN
    v_ok := true;
  END;
  RETURN NEXT ok(v_ok, 'text without x/y rejected');

  -- negative width should fail
  BEGIN
    PERFORM document.element_add(v_canvas_id, 'rect', 0, '{"x":0,"y":0,"width":-10,"height":50}'::jsonb);
    v_ok := false;
  EXCEPTION WHEN check_violation THEN
    v_ok := true;
  END;
  RETURN NEXT ok(v_ok, 'negative width rejected');

  -- path without d in props should fail
  BEGIN
    PERFORM document.element_add(v_canvas_id, 'path', 0, '{"fill":"#000"}'::jsonb);
    v_ok := false;
  EXCEPTION WHEN check_violation THEN
    v_ok := true;
  END;
  RETURN NEXT ok(v_ok, 'path without d rejected');

  -- Cleanup
  DELETE FROM document.canvas WHERE id = v_canvas_id;
END;
$function$;
COMMENT ON FUNCTION document_ut.test_element_constraints() IS 'Test CHECK constraints reject invalid geometry per element type';

CREATE OR REPLACE FUNCTION document_ut.test_element_move()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_canvas_id uuid;
  v_e1 uuid; v_e2 uuid; v_e3 uuid;
  v_group_id uuid;
  v_moved int;
  v_row document.element;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  v_canvas_id := document.canvas_create('Move test');

  -- Create elements: rect, circle, line
  v_e1 := document.element_add(v_canvas_id, 'rect', 0, '{"x":10,"y":20,"width":100,"height":50}'::jsonb);
  v_e2 := document.element_add(v_canvas_id, 'circle', 1, '{"cx":50,"cy":60,"r":25}'::jsonb);
  v_e3 := document.element_add(v_canvas_id, 'line', 2, '{"x1":0,"y1":0,"x2":100,"y2":100}'::jsonb);

  -- Group them
  v_group_id := document.group_create(v_canvas_id, ARRAY[v_e1, v_e2, v_e3], 'movable');

  -- Move group by +10, +5
  v_moved := document.element_move(v_group_id, 10, 5);
  RETURN NEXT is(v_moved, 3, '3 elements moved');

  -- Verify rect moved
  SELECT * INTO v_row FROM document.element WHERE id = v_e1;
  RETURN NEXT ok(v_row.x = 20, 'rect x: 10+10=20');
  RETURN NEXT ok(v_row.y = 25, 'rect y: 20+5=25');

  -- Verify circle moved
  SELECT * INTO v_row FROM document.element WHERE id = v_e2;
  RETURN NEXT ok(v_row.cx = 60, 'circle cx: 50+10=60');
  RETURN NEXT ok(v_row.cy = 65, 'circle cy: 60+5=65');

  -- Verify line moved
  SELECT * INTO v_row FROM document.element WHERE id = v_e3;
  RETURN NEXT ok(v_row.x1 = 10, 'line x1: 0+10=10');
  RETURN NEXT ok(v_row.y1 = 5, 'line y1: 0+5=5');
  RETURN NEXT ok(v_row.x2 = 110, 'line x2: 100+10=110');
  RETURN NEXT ok(v_row.y2 = 105, 'line y2: 100+5=105');

  -- Move single leaf
  v_moved := document.element_move(v_e1, -5, -5);
  RETURN NEXT is(v_moved, 1, '1 element moved (single)');
  SELECT * INTO v_row FROM document.element WHERE id = v_e1;
  RETURN NEXT ok(v_row.x = 15, 'rect x after second move: 20-5=15');

  -- Cleanup
  DELETE FROM document.canvas WHERE id = v_canvas_id;
END;
$function$;
COMMENT ON FUNCTION document_ut.test_element_move() IS 'Test element_move: group recursive + single leaf + all geometry types';

CREATE OR REPLACE FUNCTION document_ut.test_group_create()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_canvas_id uuid;
  v_e1 uuid; v_e2 uuid; v_e3 uuid;
  v_group_id uuid;
  v_row document.element;
  v_cnt int;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  v_canvas_id := document.canvas_create('Group test');

  -- Create 3 sibling elements
  v_e1 := document.element_add(v_canvas_id, 'rect', 0, '{"x":0,"y":0,"width":50,"height":50}'::jsonb);
  v_e2 := document.element_add(v_canvas_id, 'rect', 1, '{"x":60,"y":0,"width":50,"height":50}'::jsonb);
  v_e3 := document.element_add(v_canvas_id, 'text', 2, '{"x":10,"y":100}'::jsonb);

  -- Group first two
  v_group_id := document.group_create(v_canvas_id, ARRAY[v_e1, v_e2], 'my-group');

  -- Verify group exists
  SELECT * INTO v_row FROM document.element WHERE id = v_group_id;
  RETURN NEXT ok(v_row.id IS NOT NULL, 'group element created');
  RETURN NEXT is(v_row.type, 'group', 'type is group');
  RETURN NEXT is(v_row.name, 'my-group', 'group name');
  RETURN NEXT ok(v_row.parent_id IS NULL, 'group parent is null (root level)');

  -- Verify children reparented
  SELECT count(*)::int INTO v_cnt FROM document.element WHERE parent_id = v_group_id;
  RETURN NEXT is(v_cnt, 2, '2 children in group');

  -- Third element still at root
  SELECT * INTO v_row FROM document.element WHERE id = v_e3;
  RETURN NEXT ok(v_row.parent_id IS NULL, 'third element still root');

  -- Cleanup
  DELETE FROM document.canvas WHERE id = v_canvas_id;
END;
$function$;
COMMENT ON FUNCTION document_ut.test_group_create() IS 'Test group_create: group siblings, verify parent_id';

CREATE OR REPLACE FUNCTION document_ut.test_group_dissolve()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_canvas_id uuid;
  v_e1 uuid; v_e2 uuid;
  v_group_id uuid;
  v_freed int;
  v_row document.element;
  v_grp_exists boolean;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  v_canvas_id := document.canvas_create('Dissolve test');

  v_e1 := document.element_add(v_canvas_id, 'rect', 0, '{"x":0,"y":0,"width":50,"height":50}'::jsonb);
  v_e2 := document.element_add(v_canvas_id, 'text', 1, '{"x":10,"y":10}'::jsonb);

  v_group_id := document.group_create(v_canvas_id, ARRAY[v_e1, v_e2], 'temp-group');

  -- Dissolve
  v_freed := document.group_dissolve(v_group_id);
  RETURN NEXT is(v_freed, 2, '2 children freed');

  -- Group element should be gone
  SELECT EXISTS(SELECT 1 FROM document.element WHERE id = v_group_id) INTO v_grp_exists;
  RETURN NEXT ok(NOT v_grp_exists, 'group element deleted');

  -- Children back to root
  SELECT * INTO v_row FROM document.element WHERE id = v_e1;
  RETURN NEXT ok(v_row.parent_id IS NULL, 'child 1 back to root');
  SELECT * INTO v_row FROM document.element WHERE id = v_e2;
  RETURN NEXT ok(v_row.parent_id IS NULL, 'child 2 back to root');

  -- Cleanup
  DELETE FROM document.canvas WHERE id = v_canvas_id;
END;
$function$;
COMMENT ON FUNCTION document_ut.test_group_dissolve() IS 'Test group_dissolve: children reparented, group deleted';

CREATE OR REPLACE FUNCTION document_ut.test_group_nested()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_canvas_id uuid;
  v_e1 uuid; v_e2 uuid; v_e3 uuid;
  v_g1 uuid; v_g2 uuid;
  v_state jsonb;
  v_nested_cnt int;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  v_canvas_id := document.canvas_create('Nested test');

  -- Create elements
  v_e1 := document.element_add(v_canvas_id, 'rect', 0, '{"x":0,"y":0,"width":50,"height":50}'::jsonb);
  v_e2 := document.element_add(v_canvas_id, 'rect', 1, '{"x":60,"y":0,"width":50,"height":50}'::jsonb);
  v_e3 := document.element_add(v_canvas_id, 'text', 2, '{"x":10,"y":100}'::jsonb);

  -- Group e1+e2 into g1
  v_g1 := document.group_create(v_canvas_id, ARRAY[v_e1, v_e2], 'outer');

  -- Group g1+e3 into g2 (nested: g2 contains g1 which contains e1,e2)
  v_g2 := document.group_create(v_canvas_id, ARRAY[v_g1, v_e3], 'wrapper');

  -- Verify state
  v_state := document.canvas_get_state(v_canvas_id);
  RETURN NEXT ok(jsonb_array_length(v_state->'elements') = 5, '5 elements total (2 groups + 3 shapes)');

  -- g2 is root
  RETURN NEXT ok(
    (SELECT e->>'parent_id' IS NULL FROM jsonb_array_elements(v_state->'elements') e WHERE e->>'id' = v_g2::text),
    'wrapper group at root'
  );

  -- g1 is child of g2
  RETURN NEXT ok(
    (SELECT e->>'parent_id' = v_g2::text FROM jsonb_array_elements(v_state->'elements') e WHERE e->>'id' = v_g1::text),
    'outer group inside wrapper'
  );

  -- e1 is child of g1
  RETURN NEXT ok(
    (SELECT e->>'parent_id' = v_g1::text FROM jsonb_array_elements(v_state->'elements') e WHERE e->>'id' = v_e1::text),
    'rect inside outer group'
  );

  -- Count elements with parent_id set
  SELECT count(*)::int INTO v_nested_cnt
  FROM jsonb_array_elements(v_state->'elements') e
  WHERE e->>'parent_id' IS NOT NULL;
  RETURN NEXT is(v_nested_cnt, 4, '4 elements have parent_id (g1, e1, e2, e3)');

  -- Cleanup
  DELETE FROM document.canvas WHERE id = v_canvas_id;
END;
$function$;
COMMENT ON FUNCTION document_ut.test_group_nested() IS 'Test nested groups: group inside group, verify state tree';

CREATE OR REPLACE FUNCTION document_ut.test_session_sync()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_canvas_id uuid;
  v_state jsonb;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  v_canvas_id := document.canvas_create('Session test');

  -- Default state (no session row)
  v_state := document.session_get(v_canvas_id);
  RETURN NEXT is(v_state->>'phase', 'idle', 'default phase is idle');
  RETURN NEXT ok((v_state->>'zoom')::real = 1, 'default zoom is 1');

  -- Sync
  PERFORM document.session_sync(v_canvas_id, '["id1","id2"]'::jsonb, 'selected', 1.5);
  v_state := document.session_get(v_canvas_id);
  RETURN NEXT is(v_state->>'phase', 'selected', 'phase updated to selected');
  RETURN NEXT ok((v_state->>'zoom')::real = 1.5, 'zoom updated to 1.5');
  RETURN NEXT ok(jsonb_array_length(v_state->'selected_ids') = 2, '2 selected ids');

  -- Update sync
  PERFORM document.session_sync(v_canvas_id, '[]'::jsonb, 'idle', 2.0);
  v_state := document.session_get(v_canvas_id);
  RETURN NEXT is(v_state->>'phase', 'idle', 'phase back to idle');
  RETURN NEXT ok(jsonb_array_length(v_state->'selected_ids') = 0, '0 selected ids');

  -- Cleanup
  DELETE FROM document.session WHERE canvas_id = v_canvas_id;
  DELETE FROM document.canvas WHERE id = v_canvas_id;
END;
$function$;
COMMENT ON FUNCTION document_ut.test_session_sync() IS 'Test session sync and get';

CREATE OR REPLACE FUNCTION document_ut.test_session_toast()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_canvas_id uuid;
  v_state jsonb;
  v_toast jsonb;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  v_canvas_id := document.canvas_create('Toast test');

  -- Set toast
  PERFORM document.session_toast(v_canvas_id, 'Element added', 'success', 2000);
  v_state := document.session_get(v_canvas_id);
  v_toast := v_state->'toast';

  RETURN NEXT ok(v_toast IS NOT NULL, 'toast is set');
  RETURN NEXT is(v_toast->>'text', 'Element added', 'toast text matches');
  RETURN NEXT is(v_toast->>'level', 'success', 'toast level matches');
  RETURN NEXT ok((v_toast->>'duration')::int = 2000, 'toast duration matches');
  RETURN NEXT ok(v_toast ? 'at', 'toast has timestamp');

  -- Canvas get_state includes session
  v_state := document.canvas_get_state(v_canvas_id);
  RETURN NEXT ok(v_state ? 'session', 'canvas_get_state has session key');
  RETURN NEXT is(v_state->'session'->'toast'->>'text', 'Element added', 'session toast in canvas state');

  -- Cleanup
  DELETE FROM document.session WHERE canvas_id = v_canvas_id;
  DELETE FROM document.canvas WHERE id = v_canvas_id;
END;
$function$;
COMMENT ON FUNCTION document_ut.test_session_toast() IS 'Test session toast and canvas_get_state integration';

CREATE OR REPLACE FUNCTION document_ut.test_template()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id1 uuid;
  v_id2 uuid;
  v_row document.template;
  v_cnt int;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  -- Insert templates
  INSERT INTO document.template (name, doc_type, format, is_default)
  VALUES ('Facture standard', 'facture', 'A4', true)
  RETURNING id INTO v_id1;

  INSERT INTO document.template (name, doc_type, format)
  VALUES ('Devis premium', 'devis', 'A4')
  RETURNING id INTO v_id2;

  -- List all
  SELECT count(*)::int INTO v_cnt FROM document.list_templates();
  RETURN NEXT ok(v_cnt >= 2, 'list_templates returns at least 2');

  -- List by type
  SELECT count(*)::int INTO v_cnt FROM document.list_templates('facture');
  RETURN NEXT ok(v_cnt >= 1, 'list_templates filters by doc_type');

  -- Get by ID
  v_row := document.get_template(v_id1);
  RETURN NEXT is(v_row.name, 'Facture standard', 'get_template returns correct name');
  RETURN NEXT ok(v_row.is_default, 'is_default true');

  -- Cleanup
  DELETE FROM document.template WHERE id IN (v_id1, v_id2);
END;
$function$;
COMMENT ON FUNCTION document_ut.test_template() IS 'Test template CRUD operations';

